import { hasRelationPair } from '../../relation/relation';
import { getTrait, hasTrait, registerTrait } from '../../trait/trait';
import { getTraitInstance, hasTraitInstance } from '../../trait/trait-instance';
import type { Trait } from '../../trait/types';
import type { World } from '../../world';
import type { Predicate, QueryInstance } from '../types';
import { checkQueryWithRelations } from './check-query-with-relations';

export type PredicateRuntime = {
    deps: Trait[];
    predicateFn: (data: any[]) => boolean;
    /** Current evaluated value per entity id */
    values: (boolean | undefined)[];
    /** Non-tracking queries referencing this predicate (bare/Not/Or usage) */
    queries: Set<QueryInstance>;
    /** Tracking queries referencing this predicate (Added/Removed/Changed usage) */
    trackingQueries: Set<QueryInstance>;
};

export function evaluatePredicateValue(world: World, entity: Entity, runtime: PredicateRuntime): boolean {
    const data: any[] = [];
    for (const dep of runtime.deps) {
        if (!hasTrait(world, entity, dep)) return false;
        data.push(getTrait(world, entity, dep));
    }
