import type { Entity } from '../../entity/types';
import { getEntityId } from '../../entity/utils/pack-entity';
import { hasRelationPair } from '../../relation/relation';
import { getTrait, hasTrait, registerTrait } from '../../trait/trait';
import { getTraitInstance, hasTraitInstance } from '../../trait/trait-instance';
import type { Trait } from '../../trait/types';
import type { World } from '../../world';
import type { Predicate, QueryInstance } from '../types';
import { checkQueryWithRelations } from './check-query-with-relations';

export type PredicateRuntime = {
    deps: Trait[];
    predicateFn: (data: any[]) => boolean;
    /** Current evaluated value per entity id */
    values: (boolean | undefined)[];
    /** Non-tracking queries referencing this predicate (bare/Not/Or usage) */
    queries: Set<QueryInstance>;
    /** Tracking queries referencing this predicate (Added/Removed/Changed usage) */
    trackingQueries: Set<QueryInstance>;
};

export function evaluatePredicateValue(world: World, entity: Entity, runtime: PredicateRuntime): boolean {
    const data: any[] = [];
    for (const dep of runtime.deps) {
        if (!hasTrait(world, entity, dep)) return false;
        data.push(getTrait(world, entity, dep));
    }
    return !!runtime.predicateFn(data);
}

export function getOrCreatePredicateRuntime(world: World, predicate: Predicate): PredicateRuntime {
    const ctx = world[$internal];
    let runtime = ctx.predicateRuntimes.get(predicate.id);
    if (runtime) return runtime;

    runtime = {
        deps: predicate.traits,
        predicateFn: predicate.predicateFn,
        values: [],
        queries: new Set(),
        trackingQueries: new Set(),
    };
    ctx.predicateRuntimes.set(predicate.id, runtime);

    for (const dep of runtime.deps) {
        if (!hasTraitInstance(ctx.traitInstances, dep)) registerTrait(world, dep);
        const instance = getTraitInstance(ctx.traitInstances, dep)!;
        if (!instance.dependentPredicates) instance.dependentPredicates = new Set();
        instance.dependentPredicates.add(predicate.id);
    }

    for (const entity of ctx.entityIndex.dense) {
        runtime.values[getEntityId(entity)] = evaluatePredicateValue(world, entity, runtime);
    }

    return runtime;
}

export function getPredicateValue(world: World, predicateId: number, entity: Entity): boolean {
    const ctx = world[$internal];
    const runtime = ctx.predicateRuntimes.get(predicateId);
    if (!runtime) return false;
    return runtime.values[getEntityId(entity)] ?? false;
}

export function checkQueryPredicateGates(world: World, query: QueryInstance, entity: Entity): boolean {
    const gates = query.predicateGates;
    if (!gates) return true;

    for (const id of gates.required) {
        if (!getPredicateValue(world, id, entity)) return false;
    }

    for (const id of gates.forbidden) {
        if (getPredicateValue(world, id, entity)) return false;
    }

    return true;
}

export function checkPredicateOrSatisfied(world: World, query: QueryInstance, entity: Entity): boolean {
    const gates = query.predicateGates;
    if (!gates || gates.or.length === 0) return false;
    for (const id of gates.or) {
        if (getPredicateValue(world, id, entity)) return true;
    }
    return false;
}

